calls.sql:
SELECT AVG(amount) AS average_order_amount
FROM orders
WHERE status = 'completed';

SELECT COUNT(*) AS active_subscriptions 
FROM subscriptions 
WHERE ended_at IS NULL;

SELECT plan, COUNT(*) AS customer_count
FROM customers
GROUP BY plan;

SELECT event_name, COUNT(*) AS event_count
FROM events
GROUP BY event_name;

SELECT COUNT(*) AS customer_count 
FROM customers 
WHERE signup_date >= '2026-05-01' AND signup_date < '2026-06-01';

SELECT COUNT(*) AS order_count
FROM orders
WHERE created_at >= TIMESTAMP '2026-06-17' - INTERVAL '30 days';

SELECT COUNT(*) AS event_count
FROM events
WHERE occurred_at >= '2026-06-01' AND occurred_at < '2026-07-01';
